def generate_numbers():
    numbers = []
    for p in permutations('12345678', 4):
        num = int(''.join(p))
        if num >= 1000:
            numbers.append(num)
    return numbers

def find_close_sum(numbers):
    target = 4444
    for i in range(len(numbers)):
        for j in range(i+1, len(numbers)):
            if abs(numbers[i] + numbers[j] - target) < 10:
                return numbers[i], numbers[j]
    return None

